mapper.select:
SELECT 
    dtb_transaction_id as transactionId,
    dtb_account_num as datDepositAccountNum,
    dtb_amount as amount,
    dtb_transaction_type as transactionType,
    dtb_description as description,
    dtb_transaction_date as transactionDate
FROM deposit_transaction_tbl
WHERE dtb_account_num = #{dat_deposit_account_num}

    AND DATE(dtb_transaction_date) >= #{startDate}


    AND DATE(dtb_transaction_date) <= #{endDate}


    AND YEAR(dtb_transaction_date) = #{year}
    AND MONTH(dtb_transaction_date) = #{month}


    AND dtb_transaction_type = #{transactionType}

ORDER BY dtb_transaction_date 


        DESC


        ASC
